import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import Navbar from './components/Navbar.jsx';
import LoginPage from './pages/LoginPage.jsx';
import MoviesPage from './pages/MoviesPage.jsx';
import MovieDetailPage from './pages/MovieDetailPage.jsx';
import ProfilePage from './pages/ProfilePage.jsx';
import { auth } from './auth.js';

function ProtectedRoute({ children }) {
  return auth.isLoggedIn() ? children : <Navigate to="/login" />;
}

function App() {
  return (
    <BrowserRouter>
      <Navbar />
      <div className="container py-4">
        <Routes>
          <Route path="/" element={<Navigate to="/movies" />} />
          <Route path="/login" element={<LoginPage />} />
          <Route path="/movies" element={<MoviesPage />} />
          <Route path="/movies/:id" element={<MovieDetailPage />} />
          <Route
            path="/profile"
            element={
              <ProtectedRoute>
                <ProfilePage />
              </ProtectedRoute>
            }
          />
        </Routes>
      </div>
    </BrowserRouter>
  );
}

export default App;

const API = '';

async function request(path, options = {}) {
  const res = await fetch(`${API}${path}`, {
    headers: { 'Content-Type': 'application/json' },
    ...options
  });

  if (!res.ok) {
    const text = await res.text();
    let message = `HTTP ${res.status}`;
    try {
      const parsed = text ? JSON.parse(text) : null;
      message = parsed?.error || parsed?.message || message;
    } catch {
      if (text) message = text;
    }
    throw new Error(message);
  }

  if (res.status === 204) return null;
  const bodyText = await res.text();
  if (!bodyText) return null;
  return JSON.parse(bodyText);
}

export const api = {
  login: (username, parola) =>
    request('/api/auth/login', {
      method: 'POST',
      body: JSON.stringify({ username, parola })
    }),
  getFilme: () => request('/api/filme'),
  getFilmeByCategorie: (idCategorie) => request(`/api/filme/categorie/${idCategorie}`),
  getFilm: (id) => request(`/api/filme/${id}`),
  getCategorii: () => request('/api/categorii'),
  getRecenziiFilm: (idFilm) => request(`/api/recenzii/film/${idFilm}`),
  postRecenzie: (data) =>
    request('/api/recenzii', { method: 'POST', body: JSON.stringify(data) }),
  getEtichete: () => request('/api/etichete'),
  addEticheta: (idRecenzie, idEticheta) =>
    request(`/api/recenzii-etichete/${idRecenzie}/${idEticheta}`, { method: 'POST' }),
  postVizualizare: (data) =>
    request('/api/vizualizari', { method: 'POST', body: JSON.stringify(data) }),
  updateVizualizare: (idVizualizare, data) =>
    request(`/api/vizualizari/${idVizualizare}`, {
      method: 'PUT',
      body: JSON.stringify(data)
    }),
  getIstoric: (idClient) => request(`/api/vizualizari/client/${idClient}`),
  getRecomandari: (idClient) => request(`/api/stats/recomandari/${idClient}`),
  getProfil: (idClient) => request(`/api/stats/profil/${idClient}`),
  getSimilari: (idClient, topN = 5) =>
    request(`/api/stats/similari/${idClient}?topN=${topN}`),
  getActoriFilm: (idFilm) => request(`/api/actori/film/${idFilm}`)
};

const KEY = 'movieapp_user';

export const auth = {
  save: (user) => localStorage.setItem(KEY, JSON.stringify(user)),
  get: () => {
    const data = localStorage.getItem(KEY);
    return data ? JSON.parse(data) : null;
  },
  clear: () => localStorage.removeItem(KEY),
  isLoggedIn: () => localStorage.getItem(KEY) !== null
};

function formatLabel(denumire = '') {
  return denumire
    .toLowerCase()
    .replace(/_/g, ' ')
    .replace(/^./, (c) => c.toUpperCase());
}

function EticheteSelector({ etichete, selected, onToggle }) {
  const grupate = {
    POZITIV: etichete.filter((e) => e.sentiment === 'POZITIV'),
    NEGATIV: etichete.filter((e) => e.sentiment === 'NEGATIV'),
    NEUTRU: etichete.filter((e) => e.sentiment === 'NEUTRU')
  };

  const culori = {
    POZITIV: 'success',
    NEGATIV: 'danger',
    NEUTRU: 'secondary'
  };

  return (
    <div>
      {Object.entries(grupate).map(([sentiment, list]) => (
        <div key={sentiment} className="mb-3">
          <div className="text-uppercase small text-muted mb-2">{sentiment}</div>
          <div className="d-flex flex-wrap gap-2">
            {list.length === 0 && <span className="text-muted small">-</span>}
            {list.map((et) => {
              const isSelected = selected.has(et.id);
              const variant = culori[sentiment];
              return (
                <button
                  key={et.id}
                  type="button"
                  className={`btn btn-sm ${
                    isSelected ? `btn-${variant}` : `btn-outline-${variant}`
                  }`}
                  onClick={() => onToggle(et.id)}
                >
                  {formatLabel(et.denumire)}
                </button>
              );
            })}
          </div>
        </div>
      ))}
    </div>
  );
}

export default EticheteSelector;

import MoviePoster from './MoviePoster';

function MovieCard({ movie, onClick }) {
  return (
    <div className="card h-100" style={{ cursor: 'pointer' }} onClick={onClick}>
      {/* Add a compact poster placeholder */}
      <div className="card-img-top">
        <MoviePoster movie={movie} height={160} />
      </div>
      <div className="card-body">
        <h5 className="card-title">{movie.titlu}</h5>
        <p className="card-text small text-muted">
          {movie.descriere ? `${movie.descriere.substring(0, 100)}...` : 'Fara descriere'}
        </p>
        <div className="d-flex justify-content-between">
          <small>⭐ {movie.rating?.toFixed?.(1) || movie.rating || 'N/A'}</small>
          <small>{movie.dataLansare || movie.data_lansare || ''}</small>
        </div>
      </div>
    </div>
  );
}

export default MovieCard;

import { Link, useNavigate } from 'react-router-dom';
import { auth } from '../auth.js';

function Navbar() {
  const navigate = useNavigate();
  const user = auth.get();

  const handleLogout = () => {
    auth.clear();
    navigate('/login');
  };

  return (
    <nav className="navbar navbar-expand-lg navbar-dark bg-dark">
      <div className="container">
        <Link className="navbar-brand" to="/movies">
           MovieApp
        </Link>
        <div className="collapse navbar-collapse show">
          <ul className="navbar-nav me-auto mb-2 mb-lg-0">
            <li className="nav-item">
              <Link className="nav-link" to="/movies">
                Filme
              </Link>
            </li>
            {user && (
              <li className="nav-item">
                <Link className="nav-link" to="/profile">
                  Profil
                </Link>
              </li>
            )}
          </ul>
          <div className="d-flex align-items-center gap-2">
            {user ? (
              <>
                <span className="text-light small">Salut, {user.nume}!</span>
                <button className="btn btn-outline-light btn-sm" onClick={handleLogout}>
                  Logout
                </button>
              </>
            ) : (
              <Link className="btn btn-outline-light btn-sm" to="/login">
                Login
              </Link>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
}

export default Navbar;

import { useEffect, useState } from 'react';
import { api } from '../api.js';
import EticheteSelector from './EticheteSelector.jsx';

function ReviewForm({ idFilm, idClient, onSubmitted }) {
  const [nota, setNota] = useState(8);
  const [textComentariu, setTextComentariu] = useState('');
  const [etichete, setEtichete] = useState([]);
  const [selected, setSelected] = useState(new Set());
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    let ignore = false;
    api
      .getEtichete()
      .then((data) => {
        if (!ignore) setEtichete(data || []);
      })
      .catch((err) => {
        if (!ignore) setError(err.message);
      });
    return () => {
      ignore = true;
    };
  }, []);

  const toggle = (id) => {
    const copy = new Set(selected);
    if (copy.has(id)) copy.delete(id);
    else copy.add(id);
    setSelected(copy);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const recenzie = await api.postRecenzie({
        idClient,
        idFilm,
        nota: Number(nota),
        textComentariu
      });

      const idRecenzie = recenzie?.id || recenzie?.idRecenzie;
      for (const idEticheta of selected) {
        await api.addEticheta(idRecenzie, idEticheta);
      }
      setTextComentariu('');
      setSelected(new Set());
      if (onSubmitted) onSubmitted();
    } catch (err) {
      const message = err.message || 'Eroare la trimiterea recenziei.';
      if (message.includes('409') || message.toLowerCase().includes('deja')) {
        setError('Ai recenzat deja acest film.');
      } else {
        setError(message);
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="card card-body">
      <h5 className="mb-3">Adauga o recenzie</h5>
      {error && <div className="alert alert-danger">{error}</div>}
      <div className="mb-3">
        <label className="form-label">Nota (1-10)</label>
        <input
          type="number"
          min="1"
          max="10"
          className="form-control"
          value={nota}
          onChange={(e) => setNota(e.target.value)}
        />
      </div>
      <div className="mb-3">
        <label className="form-label">Comentariu</label>
        <textarea
          className="form-control"
          rows="3"
          value={textComentariu}
          onChange={(e) => setTextComentariu(e.target.value)}
        />
      </div>

      <div className="mb-3">
        <label className="form-label">Etichete</label>
        <EticheteSelector etichete={etichete} selected={selected} onToggle={toggle} />
      </div>

      <button className="btn btn-primary" type="submit" disabled={loading}>
        {loading ? 'Se posteaza...' : 'Posteaza'}
      </button>
    </form>
  );
}

export default ReviewForm;

function ReviewList({ reviews }) {
  if (!reviews || reviews.length === 0) {
    return <div className="text-muted">Nu exista recenzii inca.</div>;
  }

  return (
    <div className="list-group">
      {reviews.map((r) => (
        <div key={r.id || `${r.idClient}-${r.idFilm}`} className="list-group-item">
          <div className="d-flex justify-content-between align-items-center">
            <strong>{r.numeClient || r.clientNume || r.username || 'Client'}</strong>
            <span className="badge bg-primary">{r.nota}</span>
          </div>
          {r.textComentariu && <p className="mb-1">{r.textComentariu}</p>}
          {r.dataPostare && <small className="text-muted">{r.dataPostare}</small>}
        </div>
      ))}
    </div>
  );
}

export default ReviewList;

import { useEffect, useMemo, useRef, useState } from 'react';
import { api } from '../api.js';
import { createPortal } from 'react-dom';

const SIM_DURATION_MINUTES = 90;
const SIM_DURATION_SECONDS = SIM_DURATION_MINUTES * 60;
const SPEED_SECONDS_PER_TICK = 30;
const TICK_MS = 1000;
const SKIP_PERCENT = 10;

function formatTimeFromPercent(percent) {
  const total = SIM_DURATION_SECONDS;
  const current = Math.floor((percent / 100) * total);
  const min = Math.floor(current / 60);
  const sec = Math.floor(current % 60);
  return `${min}:${sec.toString().padStart(2, '0')}`;
}

function VideoPlayerModal({ movie, idClient, onClose }) {
  const [progress, setProgress] = useState(0);
  const [isPlaying, setIsPlaying] = useState(true);
  const [isDragging, setIsDragging] = useState(false);
  const [wasPlayingBeforeDrag, setWasPlayingBeforeDrag] = useState(false);
  const [stare, setStare] = useState('IN_PROGRESS');
  const [idVizualizare, setIdVizualizare] = useState(null);
  const [lastSyncAt, setLastSyncAt] = useState(null);
  const [error, setError] = useState('');
  const [hoverPercent, setHoverPercent] = useState(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [nowTs, setNowTs] = useState(Date.now());
  const intervalRef = useRef(null);
  const barRef = useRef(null);

  const durataMinute = useMemo(() => Math.round((progress / 100) * SIM_DURATION_MINUTES), [progress]);

  const lastSyncLabel = useMemo(() => {
    if (!lastSyncAt) return 'n/a';
    const seconds = Math.max(0, Math.floor((nowTs - lastSyncAt) / 1000));
    return `${seconds}s`;
  }, [lastSyncAt, nowTs]);

  const updateNow = () => setNowTs(Date.now());

  useEffect(() => {
    const t = setInterval(updateNow, 1000);
    return () => clearInterval(t);
  }, []);

  const saveInitial = async () => {
    try {
      const res = await api.postVizualizare({
        idClient,
        idVersiune: 1,
        durata: 0,
        stare: 'IN_PROGRESS'
      });
      const vizId = res?.id || res?.idVizualizare || res?.id_vizualizare;
      setIdVizualizare(vizId || null);
      setLastSyncAt(Date.now());
    } catch (err) {
      setError(err.message || 'Eroare la inregistrare.');
    }
  };

  const updateVizualizare = async (status, durataValue) => {
    if (!idVizualizare) return;
    try {
      await api.updateVizualizare(idVizualizare, {
        id: idVizualizare,
        idClient,
        idVersiune: 1,
        durata: durataValue,
        stare: status
      });
      setLastSyncAt(Date.now());
    } catch (err) {
      setError(err.message || 'Eroare la actualizare.');
    }
  };

  useEffect(() => {
    saveInitial();
  }, []);

  useEffect(() => {
    if (!isPlaying || isDragging || stare === 'COMPLETED') {
      if (intervalRef.current) {
        clearInterval(intervalRef.current);
        intervalRef.current = null;
      }
      return undefined;
    }

    intervalRef.current = setInterval(() => {
      setProgress((prev) => Math.min(100, prev + (SPEED_SECONDS_PER_TICK / SIM_DURATION_SECONDS) * 100));
    }, TICK_MS);

    return () => {
      if (intervalRef.current) {
        clearInterval(intervalRef.current);
        intervalRef.current = null;
      }
    };
  }, [isPlaying, isDragging, stare]);

  useEffect(() => {
    if (progress >= 100 && stare !== 'COMPLETED') {
      setStare('COMPLETED');
      setIsPlaying(false);
      updateVizualizare('COMPLETED', SIM_DURATION_MINUTES);
    }
  }, [progress, stare]);

  useEffect(() => {
    return () => {
      if (stare !== 'COMPLETED') {
        updateVizualizare('ABANDONED', durataMinute);
      }
    };
  }, [stare, durataMinute, idVizualizare]);

  const togglePlayPause = async () => {
    if (stare === 'COMPLETED') return;
    if (isPlaying) {
      setIsPlaying(false);
      setStare('PAUSED');
      await updateVizualizare('PAUSED', durataMinute);
    } else {
      setIsPlaying(true);
      setStare('IN_PROGRESS');
    }
  };

  const skipByPercent = (delta) => {
    if (stare === 'COMPLETED') return;
    setProgress((prev) => Math.min(100, Math.max(0, prev + delta)));
  };

  const handleStop = async () => {
    setIsPlaying(false);
    setStare('ABANDONED');
    await updateVizualizare('ABANDONED', durataMinute);
    onClose();
  };

  const handleSkipEnd = async () => {
    setProgress(100);
    setStare('COMPLETED');
    setIsPlaying(false);
    await updateVizualizare('COMPLETED', SIM_DURATION_MINUTES);
  };

  const calcPercentFromClientX = (clientX) => {
    const rect = barRef.current?.getBoundingClientRect();
    if (!rect) return 0;
    const raw = ((clientX - rect.left) / rect.width) * 100;
    return Math.min(100, Math.max(0, raw));
  };

  const handleBarClick = (e) => {
    const next = calcPercentFromClientX(e.clientX);
    setProgress(next);
    updateVizualizare(stare, Math.round((next / 100) * SIM_DURATION_MINUTES));
  };

  const handleMouseMove = (e) => {
    const next = calcPercentFromClientX(e.clientX);
    setHoverPercent(next);
    if (!isDragging) return;
    setProgress(next);
  };

  const handleMouseLeave = () => setHoverPercent(null);

  const handleDragStart = (e) => {
    setWasPlayingBeforeDrag(isPlaying);
    setIsDragging(true);
    setIsPlaying(false);
    setStare('PAUSED');
    const next = calcPercentFromClientX(e.clientX);
    setProgress(next);
    updateVizualizare('PAUSED', Math.round((next / 100) * SIM_DURATION_MINUTES));
  };

  const handleDragEnd = async () => {
    setIsDragging(false);
    const shouldResume = wasPlayingBeforeDrag && progress < 100;
    setIsPlaying(shouldResume);
    setStare(progress >= 100 ? 'COMPLETED' : shouldResume ? 'IN_PROGRESS' : 'PAUSED');
    await updateVizualizare(shouldResume ? 'IN_PROGRESS' : 'PAUSED', durataMinute);
  };

  useEffect(() => {
    if (!isDragging) return undefined;
    const onMove = (e) => handleMouseMove(e);
    const onUp = () => handleDragEnd();
    window.addEventListener('mousemove', onMove);
    window.addEventListener('mouseup', onUp);
    return () => {
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('mouseup', onUp);
    };
  }, [isDragging, progress, wasPlayingBeforeDrag]);

  const displayTime = `${formatTimeFromPercent(progress)} / ${formatTimeFromPercent(100)}`;

  return createPortal(
    <div className="modal fade show d-block" tabIndex="-1" role="dialog">
      <div className={`modal-dialog modal-xl ${isFullscreen ? 'modal-fullscreen' : ''}`} role="document">
        <div className="modal-content" onClick={(e) => e.stopPropagation()}>
          <div className="modal-header">
            <h5 className="modal-title">{movie.titlu}</h5>
            <button type="button" className="btn-close" onClick={handleStop}></button>
          </div>
          <div className="modal-body">
            <div className="fake-player">
              <div className="fake-poster">
                <div className="fake-poster-title">{movie.titlu}</div>
                <div className="play-pulse">▶</div>
              </div>
              <div className="player-controls">
                <button className="btn btn-light btn-sm" onClick={() => skipByPercent(-SKIP_PERCENT)}>
                  ⏮
                </button>
                <button className="btn btn-light btn-sm" onClick={togglePlayPause}>
                  {isPlaying ? '⏸' : '▶'}
                </button>
                <button className="btn btn-light btn-sm" onClick={() => skipByPercent(SKIP_PERCENT)}>
                  ⏭
                </button>
                <div className="player-time">{displayTime}</div>
                <button className="btn btn-light btn-sm" onClick={() => setIsFullscreen((v) => !v)}>
                  ⛶
                </button>
              </div>
              <div
                className="progress progress-interactive"
                ref={barRef}
                onClick={handleBarClick}
                onMouseMove={handleMouseMove}
                onMouseLeave={handleMouseLeave}
                onMouseDown={handleDragStart}
              >
                <div
                  className="progress-bar"
                  role="progressbar"
                  style={{ width: `${progress}%` }}
                  aria-valuenow={progress}
                  aria-valuemin="0"
                  aria-valuemax="100"
                ></div>
                {hoverPercent !== null && (
                  <div
                    className="progress-hover"
                    style={{ left: `${hoverPercent}%` }}
                  >
                    {formatTimeFromPercent(hoverPercent)}
                  </div>
                )}
              </div>
              <div className="player-debug">
                <span>Stare: {stare}</span>
                <span>• Inregistrare: live BD</span>
              </div>
            </div>
            <div className="player-debug-panel">
              <div>ID Vizualizare: {idVizualizare || '-'}</div>
              <div>Stare curenta: {stare}</div>
              <div>Durata salvata: {durataMinute} min</div>
              <div>Ultima sincronizare BD: {lastSyncLabel}</div>
            </div>
            {error && <div className="alert alert-danger mt-3">{error}</div>}
          </div>
          <div className="modal-footer">
            <button className="btn btn-outline-danger" onClick={handleStop}>
              Stop
            </button>
            <button className="btn btn-primary" onClick={handleSkipEnd}>
              Skip to end
            </button>
          </div>
        </div>
      </div>
      <div className="modal-backdrop fade show"></div>
    </div>,
    document.body
  );
}

export default VideoPlayerModal;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App.jsx';
import './styles.css';

ReactDOM.createRoot(document.getElementById('root')).render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { api } from '../api.js';
import { auth } from '../auth.js';

function LoginPage() {
  const [username, setUsername] = useState('');
  const [parola, setParola] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const user = await api.login(username, parola);
      auth.save(user);
      navigate('/movies');
    } catch (err) {
      setError(err.message || 'Autentificare esuata.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="row justify-content-center">
      <div className="col-md-6 col-lg-5">
        <div className="card card-body shadow-sm">
          <h4 className="mb-3">Autentificare</h4>
          {error && <div className="alert alert-danger">{error}</div>}
          <form onSubmit={handleSubmit}>
            <div className="mb-3">
              <label className="form-label">Username</label>
              <input
                className="form-control"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
              />
            </div>
            <div className="mb-3">
              <label className="form-label">Parola</label>
              <input
                type="password"
                className="form-control"
                value={parola}
                onChange={(e) => setParola(e.target.value)}
              />
            </div>
            <button className="btn btn-primary w-100" disabled={loading}>
              {loading ? 'Se autentifica...' : 'Login'}
            </button>
          </form>
          <div className="text-muted small mt-3">Test: client1 / parola1</div>
        </div>
      </div>
    </div>
  );
}

export default LoginPage;

import { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { api } from '../api.js';
import { auth } from '../auth.js';
import ReviewList from '../components/ReviewList.jsx';
import ReviewForm from '../components/ReviewForm.jsx';
import VideoPlayerModal from '../components/VideoPlayerModal.jsx';
import MoviePoster from '../components/MoviePoster.jsx';

function MovieDetailPage() {
  const { id } = useParams();
  const user = auth.get();
  const [movie, setMovie] = useState(null);
  const [actors, setActors] = useState([]);
  const [reviews, setReviews] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [showPlayer, setShowPlayer] = useState(false);

  const loadAll = async () => {
    setLoading(true);
    setError('');
    try {
      const [movieData, actorData, reviewData] = await Promise.all([
        api.getFilm(id),
        api.getActoriFilm(id),
        api.getRecenziiFilm(id)
      ]);
      setMovie(movieData);
      setActors(actorData || []);
      setReviews(reviewData || []);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadAll();
  }, [id]);

  const handleVizionare = () => {
    if (!user) return;
    setShowPlayer(true);
  };

  if (loading) return <div>Se incarca...</div>;
  if (error) return <div className="alert alert-danger">{error}</div>;
  if (!movie) return <div className="text-muted">Film inexistent.</div>;

  return (
    <div className="row g-4">
      <div className="col-lg-8">
        <div className="card card-body mb-3">
          <h3 className="mb-2">{movie.titlu}</h3>
          <p className="text-muted">{movie.descriere || 'Fara descriere'}</p>
          <div className="d-flex gap-3 flex-wrap">
            <span>⭐ {movie.rating?.toFixed?.(1) || movie.rating || 'N/A'}</span>
            <span>Data lansare: {movie.dataLansare || movie.data_lansare || '-'}</span>
            <span>Categorie: {movie.idCategorie || movie.id_categorie || '-'}</span>
          </div>
          {user && (
            <button className="btn btn-success mt-3" onClick={handleVizionare}>
              Vizioneaza
            </button>
          )}
        </div>

        <div className="card card-body mb-3">
          <h5>Actori</h5>
          {actors.length === 0 ? (
            <div className="text-muted">Nu exista actori pentru acest film.</div>
          ) : (
            <ul className="list-group list-group-flush">
              {actors.map((a) => (
                <li key={a.idActor || a.id_actor} className="list-group-item">
                  {(a.numeScena || a.nume_scena || '').trim() && (
                    <strong>{a.numeScena || a.nume_scena}</strong>
                  )}{' '}
                  {a.nume} {a.prenume} — <span className="text-muted">{a.rol}</span>
                </li>
              ))}
            </ul>
          )}
        </div>

        <div className="card card-body mb-3">
          <h5>Recenzii</h5>
          <ReviewList reviews={reviews} />
        </div>

        {user && (
          <ReviewForm
            idFilm={movie.id}
            idClient={user.id}
            onSubmitted={loadAll}
          />
        )}
      </div>

      <div className="col-lg-4">
        <div className="card card-body mb-3">
          <MoviePoster movie={movie} height={260} />
          <button
            className="btn btn-primary w-100 mt-3"
            onClick={handleVizionare}
            disabled={!user}
          >
            {user ? 'Vizioneaza (simulat)' : 'Autentifica-te pentru a viziona'}
          </button>
        </div>
        <div className="card card-body">
          <h6>Detalii rapide</h6>
          <div className="small text-muted">
            Autentificarea foloseste localStorage. Vizionarea este simulata.
          </div>
        </div>
      </div>

      {showPlayer && user && (
        <VideoPlayerModal
          movie={movie}
          idClient={user.id}
          onClose={() => setShowPlayer(false)}
        />
      )}
    </div>
  );
}

export default MovieDetailPage;

import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { api } from '../api.js';
import MovieCard from '../components/MovieCard.jsx';

function MoviesPage() {
  const [filme, setFilme] = useState([]);
  const [categorii, setCategorii] = useState([]);
  const [selectedCategory, setSelectedCategory] = useState('all');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  const loadData = async (category) => {
    setLoading(true);
    setError('');
    try {
      const [cats, movies] = await Promise.all([
        api.getCategorii(),
        category === 'all' ? api.getFilme() : api.getFilmeByCategorie(category)
      ]);
      setCategorii(cats || []);
      setFilme(movies || []);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData(selectedCategory);
  }, [selectedCategory]);

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-3">
        <h3 className="mb-0">Filme</h3>
        <select
          className="form-select w-auto"
          value={selectedCategory}
          onChange={(e) => setSelectedCategory(e.target.value)}
        >
          <option value="all">Toate categoriile</option>
          {categorii.map((c) => (
            <option key={c.id} value={c.id}>
              {c.nume}
            </option>
          ))}
        </select>
      </div>

      {loading && <div>Se incarca...</div>}
      {error && <div className="alert alert-danger">{error}</div>}

      {!loading && !error && filme.length === 0 && (
        <div className="text-muted">Nu exista filme.</div>
      )}

      <div className="row g-3">
        {filme.map((movie) => (
          <div key={movie.id} className="col-md-4">
            <MovieCard movie={movie} onClick={() => navigate(`/movies/${movie.id}`)} />
          </div>
        ))}
      </div>
    </div>
  );
}

export default MoviesPage;

import { useEffect, useState } from 'react';
import { api } from '../api.js';
import { auth } from '../auth.js';
import MovieCard from '../components/MovieCard.jsx';

function ProfilePage() {
  const user = auth.get();
  const [profil, setProfil] = useState(null);
  const [recomandari, setRecomandari] = useState([]);
  const [istoric, setIstoric] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    let ignore = false;
    const load = async () => {
      setLoading(true);
      setError('');
      try {
        const [profilData, recData, istoricData] = await Promise.all([
          api.getProfil(user.id),
          api.getRecomandari(user.id),
          api.getIstoric(user.id)
        ]);
        if (!ignore) {
          setProfil(profilData);
          setRecomandari(recData || []);
          setIstoric(istoricData || []);
        }
      } catch (err) {
        if (!ignore) setError(err.message);
      } finally {
        if (!ignore) setLoading(false);
      }
    };

    load();
    return () => {
      ignore = true;
    };
  }, [user.id]);

  if (loading) return <div>Se incarca...</div>;
  if (error) return <div className="alert alert-danger">{error}</div>;

  return (
    <div className="row g-4">
      <div className="col-12">
        <h3>Profil client</h3>
      </div>

      <div className="col-md-4">
        <div className="card card-body">
          <h5>Profil cinematografic</h5>
          <div className="text-muted small mb-2">
            Date generate de procedura p_profil_cinematografic
          </div>
          {profil ? (
            <ul className="list-group list-group-flush">
              <li className="list-group-item">Categorie preferata: {profil.categoriePreferata || profil.categorie_preferata || '-'}</li>
              <li className="list-group-item">Actor preferat: {profil.actorPreferat || profil.actor_preferat || '-'}</li>
              <li className="list-group-item">Rating mediu: {profil.ratingMediu || profil.rating_mediu || '-'}</li>
              <li className="list-group-item">Total filme vazute: {profil.totalFilmeVazute || profil.total_filme_vazute || '-'}</li>
              <li className="list-group-item">Total recenzii: {profil.totalRecenzii || profil.total_recenzii || '-'}</li>
              <li className="list-group-item">Sentiment dominant: {profil.sentimentDominant || profil.sentiment_dominant || '-'}</li>
            </ul>
          ) : (
            <div className="text-muted">Nu exista date.</div>
          )}
        </div>
      </div>

      <div className="col-md-8">
        <div className="card card-body mb-4">
          <h5>Recomandari pentru tine</h5>
          <div className="text-muted small mb-2">
            Recomandari generate de procedura p_recomandari_pentru_client
          </div>
          {recomandari.length === 0 ? (
            <div className="text-muted">Nu exista recomandari.</div>
          ) : (
            <div className="row g-3">
              {recomandari.slice(0, 10).map((movie) => (
                <div key={movie.id || movie.id_film} className="col-md-6">
                  <MovieCard movie={movie} onClick={() => {}} />
                </div>
              ))}
            </div>
          )}
        </div>

        <div className="card card-body">
          <h5>Istoric vizionari</h5>
          {istoric.length === 0 ? (
            <div className="text-muted">Nu exista vizionari.</div>
          ) : (
            <div className="table-responsive">
              <table className="table table-sm">
                <thead>
                  <tr>
                    <th>Titlu</th>
                    <th>Versiune</th>
                    <th>Data</th>
                    <th>Durata</th>
                    <th>Stare</th>
                  </tr>
                </thead>
                <tbody>
                  {istoric.map((v, idx) => (
                    <tr key={v.id || idx}>
                      <td>{v.titlu || v.titluFilm || v.titlu_film || '-'}</td>
                      <td>{v.versiune || v.idVersiune || v.id_versiune || '-'}</td>
                      <td>{v.dataVizualizare || v.data_vizualizare || '-'}</td>
                      <td>{v.durata || '-'}</td>
                      <td>{v.stare || '-'}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default ProfilePage;

body {
  background: #f7f7fb;
}

.card {
  border-radius: 12px;
}

.navbar-brand {
  font-weight: 600;
}

.movie-poster {
  border-radius: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #fff;
  text-align: center;
  padding: 16px;
  font-weight: 600;
}

.movie-poster-title {
  line-height: 1.3;
}

.fake-player {
  background: #f1f3f5;
  border-radius: 12px;
  padding: 16px;
}

.fake-poster {
  border-radius: 12px;
  height: 260px;
  background: linear-gradient(135deg, #343a40, #6c757d);
  display: flex;
  align-items: center;
  justify-content: center;
  color: #fff;
  font-weight: 600;
  text-align: center;
  padding: 16px;
}

.fake-poster-title {
  font-size: 1.1rem;
}

.play-pulse {
  position: absolute;
  width: 64px;
  height: 64px;
  border-radius: 50%;
  background: rgba(0, 0, 0, 0.5);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 28px;
  animation: pulse 1.6s infinite;
}

.fake-poster {
  position: relative;
}

@keyframes pulse {
  0% {
    transform: scale(1);
    opacity: 0.8;
  }
  70% {
    transform: scale(1.15);
    opacity: 0.4;
  }
  100% {
    transform: scale(1);
    opacity: 0.8;
  }
}

.player-controls {
  margin-top: 12px;
  display: flex;
  align-items: center;
  gap: 8px;
}

.player-time {
  margin-left: auto;
  font-size: 0.85rem;
  color: #6c757d;
}

.progress-interactive {
  margin-top: 10px;
  height: 10px;
  cursor: pointer;
  position: relative;
}

.progress-hover {
  position: absolute;
  top: -28px;
  transform: translateX(-50%);
  background: #212529;
  color: #fff;
  padding: 2px 6px;
  border-radius: 6px;
  font-size: 0.75rem;
  pointer-events: none;
}

.player-debug {
  margin-top: 10px;
  font-size: 0.8rem;
  color: #6c757d;
}

.player-debug-panel {
  margin-top: 12px;
  padding: 10px 12px;
  background: #f8f9fa;
  border-radius: 8px;
  font-size: 0.8rem;
  color: #495057;
}

.modal {
  position: fixed;
  inset: 0;
  z-index: 1050;
  display: flex;
  align-items: center;
  justify-content: center;
}

.modal-dialog {
  z-index: 1055;
}

.modal-content {
  z-index: 1060;
}

.modal-backdrop {
  z-index: 1040;
  pointer-events: none;
}

import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';

export default defineConfig({
  plugins: [react()],
  server: {
    proxy: {
      '/api': 'http://localhost:8080'
    }
  }
});
